 13→const CharCounter = ({ current, max }) => {
 14→    const pct = (current / max) * 100;
 15→    const cls = pct >= 90 ? 'char-counter-fill--danger' : pct >= 70 ? 'char-counter-fill--warning' : 'char-counter-fill--normal';
 16→    return (
 17→        <div className="char-counter-container">
 18→            <div className="char-counter-bar">
 19→                <div className={`char-counter-fill ${cls}`} style={{ width: `${Math.min(pct, 100)}%` }} />
 20→            </div>
 21→            <span className="char-counter-text">{current}/{max}</span>
 22→        </div>
 23→    );
 24→};
